  ('cpa-moex-01101', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得基本稅額條例規定，出售下列何種金融投資商品之所得，可能計入個人基本所得額？', '["國內公司發行之公開募集基金", "國內未上市公司發行之公司債", "國外公司發行之連動式債券", "依我國金融資產證券化規定發行之受益憑證"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01102', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法及其相關法規規定，多層次傳銷事業的個人參加人，因為下層直銷商向傳銷事業進貨或購進 商品累積積分額（或金額）達一定標準，而自該事業取得的業績獎金，應申報為何類所得？', '["營利所得", "薪資所得", "執行業務所得", "其他所得"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01103', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法規定，委託人為營利事業之信託契約，明定信託利益全部屬於委託人，於信託關係存續中， 變更為非委託人者，應如何課稅？', '["由變更後受益人將其享有信託利益之權利價值，併入變更年度之所得額，依法課徵所得稅", "由變更後受益人將其享有信託利益之權利價值，併入信託契約成立年度之所得額，依法課徵所得稅", "將變更後受益人享有信託利益之權利價值，併入委託人變更年度之贈與，依法課徵贈與稅", "由受託人按該受益人享有信託利益之權利價值，採就源扣繳的方式扣繳稅款"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01104', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '當年度1月無連續三日國定假日者，依所得稅法第88條各類所得稅款之扣繳義務人，應於何時將上一年 內扣繳各納稅義務人之稅款數額，開具扣繳憑單，彙報該管稽徵機關查核？', '["每年1月底前", "每年2月底前", "每年3月底前", "每年4月底前"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01105', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法規定，我國105年度綜合所得稅課稅級距及稅率，下列敘述何者正確？', '["分為6級，最高為40％", "分為6級，最低為6％", "分為5級，最低為6％", "分為6級，最高為45％"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01106', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '假設甲商號民國105年1、2月有銷項稅額35萬元，進項稅額35萬元，甲商號遲至105年4月20日才 申報加值型及非加值型營業稅，甲商號將被處以怠報金為新臺幣多少元？', '["0元", "1,000元", "3,000元", "30,000元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01107', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，保險業經營專屬本業、非專屬本業及再保費等收入之營業稅稅率分 別為若干？', '["5%；5%；2%", "2%；5%；1%", "5%；5%；1%", "5%；2%；1%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01108', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲公司委託乙公司管理處分信託財產，雙方訂定他益信託契約，下列何者應課徵營業稅？', '["委託人甲公司將信託財產登記為受託人乙公司名義", "委託人甲公司變更信託契約之受託人為丙公司，受託人乙公司將信託財產登記為丙公司名義", "受託人乙公司於信託關係消滅時，將委託人甲公司的信託財產返還予甲公司", "受託人乙公司於信託關係結束後，依信託契約將委託財產移轉與受益人丁公司"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01109', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '下列敘述何者不符合營業稅法規定？', '["營業人短漏開統一發票經查獲者，除補稅外，按所漏稅額處10倍以下罰鍰", "營業人一年內經查獲短漏開統一發票達3次者，主管稽徵機關應停止其營業", "營業人短漏報銷售額經查獲者，除補稅外，按所漏稅額處5倍以下罰鍰", "營業人未依規定期限申報銷售額，應加徵之滯報金，其金額不得少於新臺幣1,200元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01110', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '假設甲公司進口洋菸完稅價格為500,000元，關稅69,000元，菸酒稅5,900元，菸品健康福利捐為5,000元， 依營業稅法規定，甲公司應繳納多少元的進口營業稅？', '["25,000元", "28,450元", "28,745元", "28,995元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
